function calcOldTax(income,age){var ex=age==='above80'?500000:age==='60to80'?300000:250000;if(income<=ex)return 0;var tax=0;if(income>1000000)tax+=(income-1000000)*0.3;if(income>500000)tax+=Math.min(income-500000,500000)*0.2;if(income>ex)tax+=Math.min(income-ex,500000-ex)*0.05;return Math.max(tax,0);}
function calcNewTax(income){if(income<=400000)return 0;var tax=0;var slabs=[[400000,0.05],[400000,0.10],[400000,0.15],[400000,0.20],[400000,0.25],[Infinity,0.30]];var rem=income-400000;for(var i=0;i<slabs.length&&rem>0;i++){var amt=Math.min(rem,slabs[i][0]);tax+=amt*slabs[i][1];rem-=amt;}return tax;}
function calculateIT(){var gross=parseFloat(document.getElementById('itGross').value)||0,age=document.getElementById('itAge').value,ded=parseFloat(document.getElementById('itDeductions').value)||0,std=parseFloat(document.getElementById('itStdDed').value)||0,r=document.getElementById('itResult');
if(!gross){r.className='result-box applicable';r.innerHTML='<div class="result-title">Please enter income</div>';return;}
var oldIncome=Math.max(gross-std-ded,0),newIncome=Math.max(gross-std,0);
var oldTax=calcOldTax(oldIncome,age),newTax=calcNewTax(newIncome);
if(oldIncome<=500000)oldTax=0;if(newIncome<=1200000)newTax=0;
var oldCess=oldTax*0.04,newCess=newTax*0.04;
var oldTotal=Math.round(oldTax+oldCess),newTotal=Math.round(newTax+newCess);
var better=oldTotal<=newTotal?'Old Regime':'New Regime',saving=Math.abs(oldTotal-newTotal);
r.className='result-box presumptive';
r.innerHTML='<div class="result-title">'+better+' saves you '+fmt(saving)+' more</div><div class="result-detail"><table class="limits-table" style="margin-top:10px;"><tr><th></th><th>Old Regime</th><th>New Regime</th></tr><tr><td>Gross Income</td><td>'+fmt(gross)+'</td><td>'+fmt(gross)+'</td></tr><tr><td>Std Deduction</td><td>'+fmt(std)+'</td><td>'+fmt(std)+'</td></tr><tr><td>Ch VI-A Deductions</td><td>'+fmt(ded)+'</td><td>N/A</td></tr><tr><td>Taxable Income</td><td><strong>'+fmt(oldIncome)+'</strong></td><td><strong>'+fmt(newIncome)+'</strong></td></tr><tr><td>Tax</td><td>'+fmt(Math.round(oldTax))+'</td><td>'+fmt(Math.round(newTax))+'</td></tr><tr><td>Cess (4%)</td><td>'+fmt(Math.round(oldCess))+'</td><td>'+fmt(Math.round(newCess))+'</td></tr><tr style="background:#e8f8f5;"><td><strong>Total Tax</strong></td><td><strong>'+fmt(oldTotal)+'</strong></td><td><strong>'+fmt(newTotal)+'</strong></td></tr></table></div>';}
function resetIT(){['itGross','itDeductions'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('itResult').className='result-box';}



